import{_ as t,o as i,c as a,a2 as o}from"./chunks/framework.ByXR59UU.js";const u=JSON.parse('{"title":"Mitigation Overview","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/mitigation/overview.md","filePath":"openshield-xdp/mitigation/overview.md","lastUpdated":1782412920000}'),r={name:"openshield-xdp/mitigation/overview.md"};function n(s,e,l,d,h,c){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="mitigation-overview" tabindex="-1">Mitigation Overview <a class="header-anchor" href="#mitigation-overview" aria-label="Permalink to &quot;Mitigation Overview&quot;">​</a></h1><h2 id="ban-system" tabindex="-1">Ban System <a class="header-anchor" href="#ban-system" aria-label="Permalink to &quot;Ban System&quot;">​</a></h2><ul><li><strong>Single-IP bans</strong> — inserted when suspicion reaches threshold. 13 reason codes.</li><li><strong>LPM subnet bans</strong> — CIDR-level via longest-prefix-match trie. IPv4: 1,024, IPv6: 512.</li><li><strong>Auto /24 escalation</strong> — after N single-IP bans in a /24, auto-inserts subnet ban (default N=5).</li><li><strong>Star system</strong> — 6 repeat-offender levels, multipliers ×1 to ×32.</li><li><strong>Effective threshold</strong> → <code>suspicion_threshold * 2 / (2 + ban_count)</code>, floor 10.</li></ul><h2 id="rate-limiting" tabindex="-1">Rate Limiting <a class="header-anchor" href="#rate-limiting" aria-label="Permalink to &quot;Rate Limiting&quot;">​</a></h2><ul><li><strong>Threshold scoring</strong> (default) — additive suspicion per violation, cumulative ban</li><li><strong>Token bucket</strong> — per-IP, configurable rate + burst, 1 token/packet</li></ul><h2 id="whitelist" tabindex="-1">Whitelist <a class="header-anchor" href="#whitelist" aria-label="Permalink to &quot;Whitelist&quot;">​</a></h2><p>Per-IP flags: full bypass, skip ban, skip rate, skip validation. Empty-map fast path.</p><h2 id="synproxy" tabindex="-1">SYNPROXY <a class="header-anchor" href="#synproxy" aria-label="Permalink to &quot;SYNPROXY&quot;">​</a></h2><p>SYN → cookie → XDP_TX SYN-ACK → ACK → verify → XDP_PASS.</p>',9)])])}const g=t(r,[["render",n]]);export{u as __pageData,g as default};
